import React, { useState } from "react";
import "../../styles/auth.css";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";

function Register() {
  const navigate = useNavigate();
  const { register } = useAuth();
  const [form, setForm] = useState({
    firstName: "", lastName: "", email: "",
    password: "", confirmPassword: "",
    phone: "", gender: "", dob: "", role: "freelancer",
  });
  const [message, setMessage] = useState("");
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleRegister = async (e) => {
    e.preventDefault();
    setMessage("");
    if (form.password !== form.confirmPassword) { setMessage("❌ Passwords do not match!"); return; }
    if (form.phone.length !== 10) { setMessage("❌ Enter valid 10-digit phone!"); return; }
    setLoading(true);
    const result = await register({
      name: `${form.firstName} ${form.lastName}`.trim(),
      email: form.email, password: form.password,
      phone: form.phone, gender: form.gender, dob: form.dob, role: form.role,
    });
    setLoading(false);
    if (result.success) {
      setMessage("✅ Registered! Redirecting...");
      setTimeout(() => navigate("/login"), 1500);
    } else { setMessage(result.message); }
  };

  const inp = {
    width: "100%", padding: "5px 8px", fontSize: "11px",
    borderRadius: "5px", border: "1px solid #d1d5db",
    outline: "none", background: "#f9fafb", boxSizing: "border-box",
    height: "28px",
  };
  const lbl = { fontSize: "10px", fontWeight: "600", color: "#4b5563", marginBottom: "2px", display: "block" };
  const mb6 = { marginBottom: "5px" };

  return (
    <div className="register-page">

      {/* LEFT PANEL */}
      <div className="auth-left-panel">
        <h1 style={{ fontSize: "24px", marginBottom: "10px" }}>Join<br /><span>FreelanceHub</span></h1>
        <p style={{ fontSize: "12px", marginBottom: "20px" }}>Connect with top talent or find exciting projects today.</p>
        <div style={{ display: "flex", flexDirection: "column", gap: "10px" }}>
          {[["💻","Freelancers — showcase skills & get hired"],
            ["🏢","Clients — post projects & find experts"],
            ["💬","Chat directly with your team"],
            ["📊","Track earnings and project progress"]
          ].map(([icon, text], i) => (
            <div key={i} style={{ display: "flex", alignItems: "center", gap: "10px", color: "rgba(255,255,255,0.85)", fontSize: "12px" }}>
              <div style={{ width: "26px", height: "26px", background: "rgba(255,255,255,0.1)", borderRadius: "6px", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "12px", flexShrink: 0 }}>{icon}</div>
              <span>{text}</span>
            </div>
          ))}
        </div>
      </div>

      {/* RIGHT PANEL */}
      <div className="auth-right-panel" style={{ padding: "12px", overflowY: "auto", alignItems: "center" }}>
        <div style={{
          width: "100%", maxWidth: "360px",
          background: "white", padding: "14px 18px",
          borderRadius: "12px",
          boxShadow: "0 2px 16px rgba(0,0,0,0.08)",
          border: "1px solid #e5e7eb",
        }}>

          {/* HEADER */}
          <div style={{ textAlign: "center", marginBottom: "8px" }}>
            <div style={{ fontSize: "16px", marginBottom: "2px" }}>🧳</div>
            <h2 style={{ fontSize: "15px", fontWeight: "700", margin: "0 0 1px", color: "#111827" }}>Create Account</h2>
            <p style={{ fontSize: "10px", color: "#6b7280", margin: 0 }}>Join FreelanceHub today</p>
          </div>

          {/* TOGGLE */}
          <div style={{ display: "flex", background: "#f3f4f6", borderRadius: "7px", padding: "3px", marginBottom: "8px" }}>
            {[["Login", false], ["Register", true]].map(([label, active]) => (
              <button key={label}
                onClick={() => !active && navigate("/login")}
                style={{
                  flex: 1, padding: "6px", fontSize: "11px", fontWeight: "600",
                  borderRadius: "5px", border: "none", cursor: "pointer",
                  background: active ? "#0f766e" : "transparent",
                  color: active ? "white" : "#6b7280",
                  boxShadow: active ? "0 1px 4px rgba(15,118,110,0.3)" : "none",
                }}>{label}</button>
            ))}
          </div>

          {message && (
            <p style={{
              textAlign: "center", fontSize: "10px", marginBottom: "6px",
              color: message.startsWith("✅") ? "#059669" : "#ef4444",
              background: message.startsWith("✅") ? "#f0fdf4" : "#fef2f2",
              border: `1px solid ${message.startsWith("✅") ? "#bbf7d0" : "#fecaca"}`,
              padding: "4px 6px", borderRadius: "5px",
            }}>{message}</p>
          )}

          <form onSubmit={handleRegister} style={{ display: "flex", flexDirection: "column" }}>

            {/* First + Last Name */}
            <div style={{ display: "flex", gap: "6px", ...mb6 }}>
              <div style={{ flex: 1 }}>
                <label style={lbl}>First Name</label>
                <input style={inp} type="text" name="firstName" placeholder="John" value={form.firstName} onChange={handleChange} required />
              </div>
              <div style={{ flex: 1 }}>
                <label style={lbl}>Last Name</label>
                <input style={inp} type="text" name="lastName" placeholder="Doe" value={form.lastName} onChange={handleChange} required />
              </div>
            </div>

            {/* Email */}
            <div style={mb6}>
              <label style={lbl}>Email</label>
              <input style={inp} type="email" name="email" placeholder="john@example.com" value={form.email} onChange={handleChange} required />
            </div>

            {/* Password + Confirm */}
            <div style={{ display: "flex", gap: "6px", ...mb6 }}>
              <div style={{ flex: 1 }}>
                <label style={lbl}>Password</label>
                <input style={inp} type="password" name="password" placeholder="••••••••" value={form.password} onChange={handleChange} required />
              </div>
              <div style={{ flex: 1 }}>
                <label style={lbl}>Confirm</label>
                <input style={inp} type="password" name="confirmPassword" placeholder="••••••••" value={form.confirmPassword} onChange={handleChange} required />
              </div>
            </div>

            {/* Phone */}
            <div style={mb6}>
              <label style={lbl}>Phone</label>
              <input style={inp} type="tel" name="phone" placeholder="9876543210" maxLength="10" value={form.phone} onChange={handleChange} required />
            </div>

            {/* Gender + DOB */}
            <div style={{ display: "flex", gap: "6px", ...mb6 }}>
              <div style={{ flex: 1 }}>
                <label style={lbl}>Gender</label>
                <select name="gender" value={form.gender} onChange={handleChange} required style={{ ...inp, height: "28px" }}>
                  <option value="">Select</option>
                  <option value="male">Male</option>
                  <option value="female">Female</option>
                  <option value="other">Other</option>
                </select>
              </div>
              <div style={{ flex: 1 }}>
                <label style={lbl}>Date of Birth</label>
                <input style={inp} type="date" name="dob" value={form.dob} onChange={handleChange} required />
              </div>
            </div>

            {/* Role */}
            <div style={{ marginBottom: "8px" }}>
              <label style={lbl}>Register As</label>
              <div style={{ display: "flex", gap: "6px" }}>
                {[["freelancer","👤","Freelancer"],["client","👥","Client"]].map(([val, icon, label]) => (
                  <div key={val} onClick={() => setForm({ ...form, role: val })}
                    style={{
                      flex: 1, textAlign: "center", padding: "5px",
                      borderRadius: "6px", cursor: "pointer",
                      border: form.role === val ? "2px solid #0f766e" : "1px solid #e5e7eb",
                      background: form.role === val ? "#f0fdf9" : "#f9fafb",
                    }}>
                    <span style={{ fontSize: "13px" }}>{icon}</span>
                    <p style={{ fontSize: "10px", fontWeight: "600", margin: "1px 0 0", color: form.role === val ? "#0f766e" : "#6b7280" }}>{label}</p>
                  </div>
                ))}
              </div>
            </div>

            <button type="submit" disabled={loading}
              style={{
                width: "100%", padding: "8px", fontSize: "12px", fontWeight: "600",
                borderRadius: "7px", border: "none",
                background: "linear-gradient(135deg, #0f766e, #134e4a)",
                color: "white", cursor: loading ? "not-allowed" : "pointer",
                opacity: loading ? 0.7 : 1,
              }}>
              {loading ? "Creating..." : "Create Account"}
            </button>

          </form>
        </div>
      </div>
    </div>
  );
}

export default Register;
